String genererLogin(String prenom, String nom) {
    if (prenom == null || prenom.isEmpty()) return "inconnu";
    if (nom == null || nom.isEmpty()) return "inconnu";
    String prenomClean = prenom.toLowerCase().replace("-", "").replace(" ", "");
    String nomClean    = nom.toLowerCase().replace("-", "").replace(" ", "");
    String initiale    = prenomClean.substring(0, 1);
    String login       = initiale + nomClean;
    if (login.length() > 20) return login.substring(0, 20);
    return login;
}

String genererEmail(String login, String contractType) {
    if (contractType == null || contractType.isEmpty()) return "inconnu";
    String domaine;
    if (contractType.equals("Stagiaire")) {
        domaine = "@extern.banksecure.fr";
    } else if (contractType.equals("Finance") || contractType.equals("IT")) {
        domaine = "@banksecure.fr";
    } else {
        domaine = "@banksecure.fr";
    }
    String email = login + domaine;
    return email;
}
